/// <summary>
/// Extension class for form <c>CustTable</c>, Datasource <c>CustTable</c>
/// </summary>
[ExtensionOf(formDataSourceStr(CustTable, CustTable))]
internal final class ETGCustTableFDS_TradeLimit_Extension
{
}

Method.Source:
public int active()
{
    int ret = next active();

    if (ETGACFParameters::find().EnableTradeLimit == NoYes::Yes)
    {
        CustTable custTable = this.cursor();
        FormRun formRun = this.formRun();

        FormRealControl tradeLimitField = formRun.design().controlName(formControlStr(CustTable,TradeLimit_ETGTradeLimitInCustomerCurrency));
        if (tradeLimitField)
        {
            tradeLimitField.label(strFmt("Trade limit in customer currency (%1)", custTable.Currency));
        }
    }

    // Freezes the form fields by updating the design when the data source is activated.

    ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);
    //

    return ret;
}
